     1→#!/usr/bin/env npx tsx
     2→// Great Minds Daemon — Main event loop
     3→// Replaces ALL cron scripts with a single persistent process.
     4→//
     5→// Watches for:
     6→//   1. New PRDs in prds/ (chokidar file watcher)
     7→//   2. New GitHub issues (poll every 5 min)
     8→//   3. Idle → featureDream every 4 hours
     9→//   4. Memory maintenance every 6 hours
    10→//   5. Heartbeat health check every 5 min
    11→
    12→import { watch } from "chokidar";
    13→import { basename, resolve } from "path";
    14→import { readdir, stat, mkdir as mkdirAsync, rename } from "fs/promises";
    15→import { existsSync, writeFileSync, readFileSync, unlinkSync, statSync } from "fs";
    16→import { PRDS_DIR, STATUS_FILE, INTERVALS, REPO_PATH, AGENT_TIMEOUT_MS, PIPELINE_TIMEOUT_MS } from "./config.js";
    17→import { runPipeline } from "./pipeline.js";
    18→import { runFeatureDream } from "./dream.js";
    19→import { runHeartbeat, runMemoryMaintenance, processIntake } from "./health.js";
    20→import { log, logError, trimLog } from "./logger.js";
    21→import { notify } from "./telegram.js";
    22→
    23→// ─── PID Lockfile ──────────────────────────────────────────
    24→
    25→const PID_FILE = "/tmp/great-minds-daemon.pid";
    26→
    27→function acquireLock(): void {
    28→  if (existsSync(PID_FILE)) {
    29→    const oldPid = readFileSync(PID_FILE, "utf-8").trim();
    30→    try {
    31→      process.kill(Number(oldPid), 0); // Check if process exists
    32→      console.error(`FATAL: Daemon already running (PID ${oldPid}). Exiting.`);
    33→      process.exit(1);
    34→    } catch {
    35→      // Old PID is stale — remove it
    36→      unlinkSync(PID_FILE);
    37→    }
    38→  }
    39→  writeFileSync(PID_FILE, String(process.pid));
    40→  log(`PID: ${process.pid} (lockfile: ${PID_FILE})`);
    41→}
    42→
    43→function releaseLock(): void {
    44→  try { unlinkSync(PID_FILE); } catch {}
    45→}
    46→
    47→// ─── State ──────────────────────────────────────────────────
    48→
    49→let pipelineRunning = false;
    50→let pipelineAborted = false;
    51→let shuttingDown = false;
    52→let pipelineStartTime = 0;
    53→let currentlyProcessing: string | null = null;
    54→
    55→// Track last-run timestamps
    56→let lastHeartbeat = 0;
    57→let lastGitHubPoll = 0;
    58→let lastDream = 0;
    59→let lastMemoryMaintain = 0;
    60→
    61→// Queue of PRDs to process — persisted to disk
    62→const prdQueue: string[] = [];
    63→const QUEUE_FILE = resolve(REPO_PATH, ".daemon-queue.json");
    64→
    65→function saveQueue(): void {
    66→  try { writeFileSync(QUEUE_FILE, JSON.stringify(prdQueue)); } catch {}
    67→}
    68→
    69→function loadQueue(): void {
    70→  try {
    71→    if (existsSync(QUEUE_FILE)) {
    72→      const data = JSON.parse(readFileSync(QUEUE_FILE, "utf-8"));
    73→      if (Array.isArray(data)) {
    74→        for (const slug of data) {
    75→          if (typeof slug === "string" && !prdQueue.includes(slug) && !isAlreadyProcessed(`${slug}.md`)) {
    76→            prdQueue.push(slug);
    77→          }
    78→        }
    79→        log(`QUEUE: Loaded ${prdQueue.length} PRD(s) from disk`);
    80→      }
    81→    }
    82→  } catch {}
    83→}
    84→
    85→// ─── Hotfix Detection ──────────────────────────────────────
    86→
    87→function detectHotfix(prdContent: string): boolean {
    88→  // Check explicit frontmatter flag — most reliable
    89→  if (/^hotfix:\s*true/m.test(prdContent)) return true;
    90→  // Title prefix — match only the FIRST line and only an explicit
    91→  // "# fix:" / "# hotfix:" / "# patch:" prefix. The previous regex
    92→  // searched any heading anywhere for any of those words, mis-classifying
    93→  // PRDs with sub-headings like "### Config / infra" as hotfixes and
    94→  // skipping the build-gate.
    95→  const firstLine = prdContent.split("\n", 1)[0] || "";
    96→  if (/^#\s+(fix|hotfix|patch):/i.test(firstLine)) return true;
    97→  return false;
    98→}
    99→
   100→// ─── Retry Budget ──────────────────────────────────────────────────────────────────────────────────────────────────────────────
   101→
   102→const RETRY_STATE_FILE = resolve(REPO_PATH, ".daemon-retry-state.json");
   103→
   104→function getRetryCount(prdFile: string): number {
   105→  try {
   106→    if (!existsSync(RETRY_STATE_FILE)) return 0;
   107→    const data = JSON.parse(readFileSync(RETRY_STATE_FILE, "utf-8"));
   108→    return data[prdFile] || 0;
   109→  } catch { return 0; }
   110→}
   111→
   112→function incrementRetryCount(prdFile: string): void {
   113→  try {
   114→    const data = existsSync(RETRY_STATE_FILE)
   115→      ? JSON.parse(readFileSync(RETRY_STATE_FILE, "utf-8"))
   116→      : {};
   117→    data[prdFile] = (data[prdFile] || 0) + 1;
   118→    writeFileSync(RETRY_STATE_FILE, JSON.stringify(data, null, 2));
   119→  } catch {}
   120→}
   121→
   122→function resetRetryCount(prdFile: string): void {
   123→  try {
   124→    if (!existsSync(RETRY_STATE_FILE)) return;
   125→    const data = JSON.parse(readFileSync(RETRY_STATE_FILE, "utf-8"));
   126→    delete data[prdFile];
   127→    writeFileSync(RETRY_STATE_FILE, JSON.stringify(data, null, 2));
   128→  } catch {}
   129→}
   130→
   131→// ──────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────
   132→// ─── Duplicate Detection ────────────────────────────────────
   133→
   134→function isAlreadyProcessed(prdFile: string): boolean {
   135→  const completedPath = resolve(PRDS_DIR, "completed", prdFile);
   136→  if (existsSync(completedPath)) return true;
   137→
   138→  const livePath = resolve(PRDS_DIR, prdFile);
   139→  const failedPath = resolve(PRDS_DIR, "failed", prdFile);
   140→  const parkedPath = resolve(PRDS_DIR, "parked", prdFile);
   141→
   142→  for (const archivePath of [failedPath, parkedPath]) {
   143→    if (!existsSync(archivePath)) continue;
   144→    if (!existsSync(livePath)) return true;
   145→    try {
   146→      const archiveMtime = statSync(archivePath).mtimeMs;
   147→      const liveMtime = statSync(livePath).mtimeMs;
   148→      if (liveMtime <= archiveMtime) return true;
   149→    } catch {
   150→      return true;
   151→    }
   152→  }
   153→  return false;
   154→}
   155→
   156→// ─── PRD Watcher ────────────────────────────────────────────
   157→
   158→function startPrdWatcher(): void {
   159→  log("WATCHER: Watching prds/ for new files");
   160→
   161→  const watcher = watch(PRDS_DIR, {
   162→    ignoreInitial: true,
   163→    depth: 0, // Only watch top-level, not subdirectories
   164→    awaitWriteFinish: { stabilityThreshold: 2000, pollInterval: 500 },
   165→  });
   166→
   167→  watcher.on("add", (filePath: string) => {
   168→    const name = basename(filePath);
   169→    if (!name.endsWith(".md") || name === "TEMPLATE.md") return;
   170→
   171→    const slug = name.replace(/\.md$/, "");
   172→
   173→    // Skip if already processed, queued, or currently building
   174→    if (isAlreadyProcessed(name)) {
   175→      log(`WATCHER: Skipping "${name}" — already processed`);
   176→      return;
   177→    }
   178→    if (slug === currentlyProcessing) {
   179→      log(`WATCHER: Skipping "${name}" — currently building`);
   180→      return;
   181→    }
   182→
   183→    log(`WATCHER: New PRD detected — ${name}`);
   184→
   185→    if (!prdQueue.includes(slug)) {
   186→      prdQueue.push(slug);
   187→      saveQueue();
   188→      log(`QUEUE: Added "${slug}" (${prdQueue.length} in queue)`);
   189→    }
   190→  });
   191→
   192→  watcher.on("error", (err) => {
   193→    logError("File watcher error", err);
   194→  });
   195→}
   196→
   197→// ─── Scan for existing PRDs ─────────────────────────────────
   198→
   199→async function scanExistingPrds(): Promise<void> {
   200→  try {
   201→    const files = await readdir(PRDS_DIR);
   202→    for (const file of files) {
   203→      if (!file.endsWith(".md") || file === "TEMPLATE.md") continue;
   204→
   205→      // Check it's a file, not a directory
   206→      const filePath = resolve(PRDS_DIR, file);
   207→      const st = await stat(filePath);
   208→      if (st.isDirectory()) continue;
   209→
   210→      // Skip if already processed
   211→      if (isAlreadyProcessed(file)) {
   212→        log(`SCAN: Skipping "${file}" — already processed`);
   213→        continue;
   214→      }
   215→
   216→      const slug = file.replace(/\.md$/, "");
   217→      if (!prdQueue.includes(slug)) {
   218→        prdQueue.push(slug);
   219→        saveQueue();
   220→        log(`SCAN: Found pending PRD — ${file}`);
   221→      }
   222→    }
   223→  } catch {
   224→    // prds dir might not exist
   225→  }
   226→}
   227→
   228→// ─── Process next PRD from queue ────────────────────────────
   229→
   230→async function processNextPrd(): Promise<void> {
   231→  if (pipelineRunning || prdQueue.length === 0) return;
   232→
   233→  const project = prdQueue.shift()!;
   234→  saveQueue();
   235→  const prdFile = `${project}.md`;
   236→
   237→  // Final duplicate check before spending tokens
   238→  if (isAlreadyProcessed(prdFile)) {
   239→    log(`SKIP: "${project}" already processed — not rebuilding`);
   240→    return;
   241→  }
   242→
   243→  // Detect hotfix from PRD content
   244→  const prdPath = resolve(PRDS_DIR, prdFile);
   245→  let isHotfix = false;
   246→  try {
   247→    const prdContent = readFileSync(prdPath, "utf-8");
   248→    isHotfix = detectHotfix(prdContent);
   249→    if (isHotfix) log(`HOTFIX DETECTED: "${project}" — using fast pipeline path`);
   250→  } catch {}
   251→
   252→  currentlyProcessing = project;
   253→  pipelineRunning = true;
   254→  pipelineAborted = false;
   255→  pipelineStartTime = Date.now();
   256→
   257→  try {
   258→    await runPipeline(prdFile, project, isHotfix);
   259→  } catch (err) {
   260→    logError(`Pipeline failed for "${project}"`, err);
   261→
   262→    // Retry budget logic — max 3 attempts per PRD
   263→    const retries = getRetryCount(prdFile);
   264→    const maxRetries = 3;
   265→
   266→    if (!isHotfix) {
   267→      incrementRetryCount(prdFile);
   268→      if (retries + 1 >= maxRetries) {
   269→        await notify(
   270→          `Budget EXHAUSTED for *${project}* — moved to prds/parked/ after ${retries + 1} failures.
   271→Last error: \`${(err as Error)?.message || err}\``,
   272→          "warning",
   273→        ).catch(() => {});
   274→        try {
   275→          const parkDir = resolve(PRDS_DIR, "parked");
   276→          await mkdirAsync(parkDir, { recursive: true });
   277→          const prdPath = resolve(PRDS_DIR, prdFile);
   278→          if (existsSync(prdPath)) {
   279→            await rename(prdPath, resolve(parkDir, prdFile)).catch(() => {});
   280→            log(`ARCHIVE: Moved exhausted PRD ${prdFile} to prds/parked/`);
   281→          }
   282→        } catch (archiveErr) {
   283→          logError("Failed to park exhausted PRD", archiveErr);
   284→        }
   285→        // Don't requeue — budget exhausted
   286→        return;
   287→      }
   288→    }
   289→
   290→    await notify(
   291→      `Pipeline crashed for *${project}*:\n\`${err}\`\nAttempt ${retries + 1}/${maxRetries}. Requeuing for retry.`,
   292→      "critical",
   293→    ).catch(() => {});
   294→
   295→    // Requeue to end of queue for retry (budget not exhausted yet)
   296→    prdQueue.push(project);
   297→    saveQueue();
   298→    log(`ARCHIVE: Requeued "${project}" for attempt ${retries + 2}/${maxRetries}`);
   299→
   300→    // Also archive to failed/ for inspection
   301→    try {
   302→      const failedDir = resolve(PRDS_DIR, "failed");
   303→      await mkdirAsync(failedDir, { recursive: true });
   304→      const prdPath = resolve(PRDS_DIR, prdFile);
   305→      if (existsSync(prdPath)) {
   306→        await rename(prdPath, resolve(failedDir, prdFile)).catch(() => {});
   307→        log(`ARCHIVE: Moved failed PRD ${prdFile} to prds/failed/`);
   308→      }
   309→    } catch (archiveErr) {
   310→      logError("Failed to archive failed PRD", archiveErr);
   311→    }
   312→  } finally {
   313→    pipelineRunning = false;
   314→    pipelineAborted = false;
   315→    pipelineStartTime = 0;
   316→    currentlyProcessing = null;
   317→  }
   318→}
   319→
   320→// ─── Pipeline Watchdog ─────────────────────────────────────
   321→
   322→async function checkPipelineWatchdog(): Promise<void> {
   323→  if (!pipelineRunning || pipelineStartTime === 0) return;
   324→
   325→  const elapsed = Date.now() - pipelineStartTime;
   326→  if (elapsed > PIPELINE_TIMEOUT_MS) {
   327→    const minutes = (elapsed / 60_000).toFixed(1);
   328→    const msg = `WATCHDOG: Pipeline exceeded ${PIPELINE_TIMEOUT_MS / 60_000} min (${minutes} min) — flagging abort`;
   329→    log(msg);
   330→    await notify(msg, "critical").catch(() => {});
   331→    // Set abort flag — pipeline checks this between phases
   332→    // Do NOT flip pipelineRunning here — let processNextPrd's finally block handle it
   333→    pipelineAborted = true;
   334→  }
   335→}
   336→
   337→// Export for pipeline to check
   338→export function isPipelineAborted(): boolean {
   339→  return pipelineAborted;
   340→}
   341→
   342→// ─── Check GitHub issues ────────────────────────────────────
   343→
   344→async function checkGitHubIssues(): Promise<void> {
   345→  if (pipelineRunning) return;
   346→
   347→  try {
   348→    await processIntake();
   349→  } catch (err) {
   350→    logError("Intake processing failed", err);
   351→  }
   352→}
   353→
   354→// ─── Periodic Tasks ─────────────────────────────────────────
   355→
   356→async function runPeriodicTasks(): Promise<void> {
   357→  const now = Date.now();
   358→
   359→  // Heartbeat — every 5 min
   360→  if (now - lastHeartbeat >= INTERVALS.HEARTBEAT_MS) {
   361→    lastHeartbeat = now;
   362→    try {
   363→      await runHeartbeat();
   364→    } catch (err) {
   365→      logError("Heartbeat failed", err);
   366→    }
   367→  }
   368→
   369→  // GitHub issue poll — every 5 min
   370→  if (now - lastGitHubPoll >= INTERVALS.GITHUB_POLL_MS) {
   371→    lastGitHubPoll = now;
   372→    try {
   373→      await checkGitHubIssues();
   374→    } catch (err) {
   375→      logError("GitHub poll failed", err);
   376→    }
   377→  }
   378→
   379→  // featureDream — every 4 hours (only when idle)
   380→  if (!pipelineRunning && now - lastDream >= INTERVALS.DREAM_MS) {
   381→    lastDream = now;
   382→    try {
   383→      await runFeatureDream();
   384→    } catch (err) {
   385→      logError("Feature dream failed", err);
   386→    }
   387→  }
   388→
   389→  // Memory maintenance — every 6 hours
   390→  if (now - lastMemoryMaintain >= INTERVALS.MEMORY_MAINTAIN_MS) {
   391→    lastMemoryMaintain = now;
   392→    try {
   393→      runMemoryMaintenance();
   394→    } catch (err) {
   395→      logError("Memory maintenance failed", err);
   396→    }
   397→  }
   398→
   399→  // Pipeline watchdog — detect hung pipelines
   400→  await checkPipelineWatchdog();
   401→
   402→  // Trim log file periodically
   403→  trimLog(500);
   404→}
   405→
   406→// ─── Graceful Shutdown ──────────────────────────────────────
   407→
   408→function setupShutdown(): void {
   409→  const shutdown = (signal: string) => {
   410→    if (shuttingDown) return;
   411→    shuttingDown = true;
   412→    log(`SHUTDOWN: Received ${signal} — stopping gracefully`);
   413→
   414→    if (!pipelineRunning) {
   415→      log("SHUTDOWN: No pipeline running — exiting immediately");
   416→      releaseLock();
   417→      process.exit(0);
   418→    } else {
   419→      log("SHUTDOWN: Pipeline in progress — will exit when current agent finishes");
   420→      setTimeout(() => {
   421→        log("SHUTDOWN: Force exit after timeout");
   422→        releaseLock();
   423→        process.exit(1);
   424→      }, 60_000);
   425→    }
   426→  };
   427→
   428→  process.on("SIGINT", () => shutdown("SIGINT"));
   429→  process.on("SIGTERM", () => shutdown("SIGTERM"));
   430→}
   431→
   432→// ─── Main Loop ──────────────────────────────────────────────
   433→
   434→async function main(): Promise<void> {
   435→  // C1: PID lockfile — prevent duplicate daemons
   436→  acquireLock();
   437→
   438→  log("══════════════════════════════════════════════════");
   439→  log("GREAT MINDS DAEMON v2.0 — Starting");
   440→  log(`REPO: ${REPO_PATH}`);
   441→  log(`PRDs: ${PRDS_DIR}`);
   442→  log(`Loop tick: ${INTERVALS.LOOP_TICK_MS / 1000}s`);
   443→  log(`Heartbeat: every ${INTERVALS.HEARTBEAT_MS / 60_000} min`);
   444→  log(`GitHub poll: every ${INTERVALS.GITHUB_POLL_MS / 60_000} min`);
   445→  log(`Dream: every ${INTERVALS.DREAM_MS / 3_600_000} hours`);
   446→  log(`Memory: every ${INTERVALS.MEMORY_MAINTAIN_MS / 3_600_000} hours`);
   447→  log(`Agent timeout: ${AGENT_TIMEOUT_MS / 60_000} min`);
   448→  log(`Pipeline timeout: ${PIPELINE_TIMEOUT_MS / 60_000} min`);
   449→  log("══════════════════════════════════════════════════");
   450→
   451→  await notify("Daemon *started* and watching for work.", "info").catch(() => {});
   452→
   453→  setupShutdown();
   454→
   455→  // C2: Load persisted queue before scanning
   456→  loadQueue();
   457→
   458→  startPrdWatcher();
   459→  await scanExistingPrds();
   460→
   461→  if (prdQueue.length > 0) {
   462→    log(`STARTUP: ${prdQueue.length} pending PRD(s) in queue`);
   463→  } else {
   464→    log("STARTUP: No pending PRDs — entering idle mode");
   465→  }
   466→
   467→  // Run initial heartbeat
   468→  lastHeartbeat = Date.now();
   469→  lastGitHubPoll = Date.now();
   470→  try {
   471→    await runHeartbeat();
   472→  } catch (err) {
   473→    logError("Initial heartbeat failed", err);
   474→  }
   475→
   476→  // Main loop
   477→  while (!shuttingDown) {
   478→    try {
   479→      await processNextPrd();
   480→      await runPeriodicTasks();
   481→    } catch (err) {
   482→      logError("Main loop error", err);
   483→    }
   484→
   485→    await new Promise((resolve) => setTimeout(resolve, INTERVALS.LOOP_TICK_MS));
   486→  }
   487→
   488→  log("DAEMON: Exited main loop");
   489→  releaseLock();
   490→  process.exit(0);
   491→}
   492→
   493→// ─── Start ──────────────────────────────────────────────────
   494→
   495→main().catch((err) => {
   496→  logError("Fatal error", err);
   497→  releaseLock();
   498→  process.exit(1);
   499→});
   500→// ══ EXPORTS ════════════════════════════════════════════════
   501→export { getRetryCount, incrementRetryCount, resetRetryCount };
   502→

